// Détermine le pilier éditorial et le prompt selon le jour de la semaine
const now = new Date();
const day = now.getDay(); // 0=Dim, 1=Lun, 2=Mar, 3=Mer, 4=Jeu, 5=Ven, 6=Sam

const schedule = {
  1: { pillar: 'Rituel du jour',     platforms: ['instagram', 'tiktok'] },
  2: { pillar: 'Neuro & science',    platforms: ['instagram'] },
  3: { pillar: 'Ma fleur & moi',     platforms: ['instagram', 'tiktok'] },
  4: { pillar: 'Bien-être pratique', platforms: ['linkedin'] },
  5: { pillar: 'Témoignages',        platforms: ['instagram'] },
  6: { pillar: 'Bien-être pratique', platforms: ['tiktok'] },
  0: { pillar: 'Rituel du jour',     platforms: ['instagram'] },
};

const config = schedule[day] || schedule[1];

const systemPrompt = `Tu es le générateur de contenu IA de Mon Jardin Intérieur, une application de bien-être où l'utilisateur prend soin de sa \'fleur intérieure\', reflet de son état émotionnel. Philosophie : ralentir permet au cortex de baisser en intensité, activant les zones antérieures du cerveau pour libérer de l\'espace mental. Ton : personnel, poétique, ancré dans la réalité. Réponds UNIQUEMENT en JSON valide sans markdown ni explication.`;

const userPrompt = `Génère un post ${config.platforms[0]} pour le pilier "${config.pillar}".\n\nJSON attendu :\n{\n  "hook": "Accroche 1-2 phrases, arrête le scroll",\n  "caption": "Caption complète avec \\n pour les sauts de ligne, emojis naturels, question d\'engagement finale",\n  "hashtags": ["tag1", "tag2"] avec exactement 25 hashtags sans #,\n  "note_format": "Conseil de format en 1 phrase",\n  "note_heure": "Meilleure heure de publication en 1 phrase"\n}`;

return [{
  json: {
    ...config,
    systemPrompt,
    userPrompt,
    generatedAt: now.toISOString(),
    dayOfWeek: day,
  }
}];

// Parse la réponse Claude et effectue un contrôle qualité
const claudeResponse = $input.first().json;
const pillarData = $('Pilier du jour').first().json;

const rawText = claudeResponse.content?.[0]?.text || '';
const jsonMatch = rawText.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error(`Réponse Claude sans JSON valide. Début: ${rawText.substring(0, 200)}`);
}

let content;
try {
  content = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error(`Erreur de parsing JSON: ${e.message}`);
}

// Contrôle qualité — 4 critères
const checks = {
  hasHook:      (content.hook?.length || 0) > 15,
  hasCaption:   (content.caption?.length || 0) > 80,
  hasHashtags:  Array.isArray(content.hashtags) && content.hashtags.length >= 20,
  hasQuestion:  (content.caption || '').includes('?'),
};

const qualityScore = Object.values(checks).filter(Boolean).length;
const isValid = qualityScore >= 3;

return [{
  json: {
    ...content,
    pillar:       pillarData.pillar,
    platforms:    pillarData.platforms,
    generatedAt:  pillarData.generatedAt,
    isValid,
    qualityScore,
    checks,
  }
}];

